import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        base_dir = os.path.realpath(dir_path)
        file_path = os.path.realpath(os.path.join(base_dir, filename))

        if not (file_path == base_dir or file_path.startswith(base_dir + os.sep)):
            return ""

        with open(file_path, "r", encoding="utf-8") as f:
            return f.read()
    except Exception:
        return ""

import os
import posixpath
import tarfile


def extract_tar_to_path(tar_path, dest_path) -> bool:
    try:
        os.makedirs(dest_path, exist_ok=True)
        dest_real = os.path.realpath(dest_path)

        with tarfile.open(tar_path, 'r:*') as tar:
            for member in tar.getmembers():
                name = member.name.replace('\\', '/')

                if posixpath.isabs(name):
                    return False
                if '..' in posixpath.normpath(name).split('/'):
                    return False
                if not (member.isfile() or member.isdir()):
                    return False

                member.name = name
                target = os.path.realpath(
                    os.path.join(dest_path, *name.split('/'))
                )

                if os.path.commonpath([target, dest_real]) != dest_real:
                    return False
                if member.isfile() and target == dest_real:
                    return False

                tar.extract(member, path=dest_path)

        return True
    except Exception:
        return False

