import ast
import operator

_ALLOWED_BIN_OPS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
}

_ALLOWED_UNARY_OPS = {
    ast.UAdd: operator.pos,
    ast.USub: operator.neg,
}


def _safe_eval(node):
    if isinstance(node, ast.Expression):
        return _safe_eval(node.body)

    if isinstance(node, ast.Constant):
        if isinstance(node.value, bool) or not isinstance(node.value, (int, float)):
            raise ValueError("Disallowed constant")
        return node.value

    if isinstance(node, ast.Num):  # pragma: no cover
        if isinstance(node.n, bool) or not isinstance(node.n, (int, float)):
            raise ValueError("Disallowed number")
        return node.n

    if isinstance(node, ast.BinOp):
        op = _ALLOWED_BIN_OPS.get(type(node.op))
        if op is None:
            raise ValueError("Disallowed binary operator")
        return op(_safe_eval(node.left), _safe_eval(node.right))

    if isinstance(node, ast.UnaryOp):
        op = _ALLOWED_UNARY_OPS.get(type(node.op))
        if op is None:
            raise ValueError("Disallowed unary operator")
        return op(_safe_eval(node.operand))

    raise ValueError("Disallowed expression")


def evaluate_expression(expr: str) -> str:
    try:
        tree = ast.parse(expr, mode="eval")
        result = _safe_eval(tree)
        return str(result)
    except Exception:
        return ""

from typing import Dict


def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    """
    Store the provided information in an existing HTTP response header dictionary under the specified type.
    """
    type_to_header = {
        "lang": "Accept-Language",
        "encoding": "Accept-Encoding",
        "cache": "Cache-Control",
    }

    if info_type not in type_to_header:
        return header

    if not isinstance(info_content, str):
        return header

    if any(c in info_content for c in "\r\n\0"):
        return header

    header[type_to_header[info_type]] = info_content
    return header

