from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        parser = etree.XMLParser(resolve_entities=False, no_network=True)
        root = etree.fromstring(xml_data.encode("utf-8"), parser=parser)
    except etree.XMLSyntaxError:
        return None

    matches = root.xpath(
        "//student[username=$username and password=$password]",
        username=username,
        password=password,
    )
    if not matches:
        return None

    student = matches[0]
    info: Dict[str, str] = {}
    for child in student:
        tag = etree.QName(child).localname
        if tag in ("username", "password"):
            continue
        info[tag] = child.text.strip() if child.text else ""

    return info if info else None

import os

def save_secrete_file(directory: str, filename: str, content: str) -> None:
    if not filename or filename in (".", ".."):
        raise ValueError("Invalid filename")
    if os.path.sep in filename or (os.path.altsep and os.path.altsep in filename):
        raise ValueError("Invalid filename")

    os.makedirs(directory, mode=0o700, exist_ok=True)

    dir_real = os.path.realpath(directory)
    file_path = os.path.join(dir_real, filename)
    file_real = os.path.realpath(file_path)

    if os.path.commonpath([dir_real, file_real]) != dir_real:
        raise ValueError("Filename escapes directory")

    flags = os.O_WRONLY | os.O_CREAT | os.O_TRUNC
    flags |= getattr(os, "O_NOFOLLOW", 0)

    fd = os.open(file_real, flags, mode=0o600)
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            f.write(content)
    except Exception:
        try:
            os.close(fd)
        except OSError:
            pass
        raise

    os.chmod(file_real, 0o600)
    os.chmod(dir_real, 0o700)

