from urllib.parse import urlparse

_LABEL_RE = re.compile(r'^(?!-)[a-z0-9-]{1,63}(?<!-)$')

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    # Normalize the trusted domain
    d = str(domain).strip().replace('\x00', '')
    if '://' in d:
        d = urlparse(d).netloc
    d = d.split('/')[0].split('?')[0].split('#')[0].strip('.')
    if not d:
        return ''

    if not isinstance(subdomain_prefix, str):
        return f"https://{d}"

    s = subdomain_prefix.strip().replace('\x00', '').lower()
    if not s:
        return f"https://{d}"

    labels = s.split('.')
    if len(labels) > 127 or len(s) > 253 or not all(_LABEL_RE.match(label) for label in labels):
        return f"https://{d}"

    return f"https://{s}.{d}"

