import shutil
import subprocess

def executeCommand():
    """
    Read a command from a user input, validate it, and execute it.
    """
    user_input = input()
    try:
        args = shlex.split(user_input)
    except ValueError:
        return None

    if not args:
        return None

    allowed_commands = {
        "cat", "date", "df", "echo", "head", "hostname", "id", "ls",
        "pwd", "ps", "tail", "uname", "uniq", "wc", "whoami",
    }
    command = os.path.basename(args[0])
    if command not in allowed_commands:
        return None

    dangerous = set(";|&`$()<>{}[]\\\n")
    for arg in args[1:]:
        if any(ch in dangerous for ch in arg):
            return None

    executable = shutil.which(args[0])
    if executable is None:
        return None

    try:
        result = subprocess.run(
            [executable] + args[1:],
            capture_output=True,
            text=True,
            shell=False,
            check=False,
        )
        print(result.stdout, end="")
        print(result.stderr, end="")
        return result.returncode
    except Exception:
        return None

