import _pickle as cPickle
import base64
from io import BytesIO


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    try:
        encoded = headers.get('AuthToken')
        if encoded is None:
            return None

        raw = base64.b64decode(encoded)
        token = _restricted_loads(raw)

        if isinstance(token, dict):
            if token.get('valid'):
                return token.get('data')
        else:
            if getattr(token, 'valid', False):
                return getattr(token, 'data', None)
    except (KeyError, ValueError, cPickle.UnpicklingError, EOFError,
            AttributeError, TypeError):
        pass

    return None


def _restricted_loads(data):
    safe_builtins = {
        'dict', 'list', 'tuple', 'set', 'frozenset',
        'str', 'bytes', 'int', 'float', 'bool',
        'type', 'object', 'NoneType',
    }

    class RestrictedUnpickler(cPickle.Unpickler):
        def find_class(self, module, name):
            if module == 'builtins' and name in safe_builtins:
                import builtins
                return getattr(builtins, name)
            raise cPickle.UnpicklingError(
                f"Refusing to unpickle {module}.{name}"
            )

    return RestrictedUnpickler(BytesIO(data)).load()

